export const generateTreeDataToConfigData = (data: any) => {
    const configData: any = [];
    const loop = ($data: any, $pData: any) => $data.map((item: any) => {
        const cData: any = {
            title: item.title
        };
        if (item.children) {
            cData.children = [];
            loop(item.children, cData.children);
        } else {
            cData.path = item.path;
            cData.keyword = item.keyword;
            cData.abstract = item.abstract;
        }
        $pData.push(cData);
    });
    loop(data, configData);
    return configData;
};