import { RouteComponentProps, withRouter } from "react-router";
import * as React from "react";
import { connect } from "react-redux";
import { updateWidget } from "../../actions/settingActions";
import { WidgetName_Property_Explorer } from './../../constants/WidgetNames';
import { IPanes } from "../../interfaces/IPane";
import { IOpenFile, IOpenFiles } from "../../interfaces/IOpenfile";
import PropertyPanel from "./PropertyPanel";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    rightWidget: string|null;
    activePane: string|undefined;
    panes: IPanes;
    openfiles: IOpenFiles;
    updateWidget: Function;
}

const mapStateToProps = (state: any) => {
    return {
        rightWidget: state.setting.rightWidget,
        activePane: state.editor.activePane,
        panes: state.panes,
        openfiles: state.openfiles,
    }
};

const mapDispatchTpProps = {
    updateWidget
};

class PerspectiveRightPanel extends React.Component<IProps, IState> {

    generateContent = () => {
        switch(this.props.rightWidget) {
            case WidgetName_Property_Explorer:
                return <PropertyPanel />;
            default:
                return null;
        }
    };

    render() {
        return (
        <>{ this.generateContent() }</>
        );
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(PerspectiveRightPanel));