import * as React from "react";
import { RouteComponentProps, withRouter } from 'react-router';
import { connect } from "react-redux";
import { CSSProperties } from "react";
import { IUserInfo } from "../../interfaces/IAccount";
import { formatMessage } from "../../AppRouter";
import { ReactComponent as Blogger } from "../../assets/blogger.svg";
import { ReactComponent as CodeOptimization } from "../../assets/codeOptimization.svg";
import { ReactComponent as Property } from "../../assets/property.svg";
import { LocalStorageUtil } from "../../utils/LocalStorageUtil";
import { Menu, Dropdown, Button } from "antd";
import { ISite } from "../../interfaces/ISetting";
import { changeLang, getToolbarData, updateWidget } from "../../actions/settingActions";
import { updateModalName } from "../../actions/editorActions";
import { IToolbar } from "../../interfaces/ISetting";
import { WidgetName_Blog_Explorer, WidgetName_Workspace_Explorer, WidgetName_Property_Explorer } from '../../constants/WidgetNames';
import { addHTMLElementStyle } from "../../utils/addStyle";
import { Modal_Setting, Modal_Audio_Convert, Modal_Video_Convert, Modal_Images_To_Ico } from './../../constants/ModalNames';
import { WidgetPos_Bottom, WidgetPos_Center, WidgetPos_Left, WidgetPos_Right } from "../../constants/WidgetPos";
import { generateIcon } from "../../utils/generateIcon";
import { openFile } from './../../actions/editorActions';
import { updateBlogNavTreeConfig } from './../../actions/blogActions';
import { generateTreeItemIcon } from "../../actions/utils/generateTreeItemData";
import { IOpenFiles, IOpenFile } from "../../interfaces/IOpenfile";
import { IPanes } from "../../interfaces/IPane";
import { IBlogNav } from "../../interfaces/IBlog";
import { ADD_NAV_TREE_NODE_TYPE_FOLDER, ADD_NAV_TREE_NODE_TYPE_FILE } from "../../constants/AddNavTreeNodeType";
import { getTreeParentKey } from "../../utils/getTreeParentKey";
import SplitterLayout from "react-splitter-layout";
import logo from '../../assets/logo.png';
import UserToolbar from "../../components/UserToolbar";
import PerspectiveBottomPanel from './PerspectiveBottomPanel';
import PerspectiveLeftPanel from './PerspectiveLeftPanel';
import PerspectiveRightPanel from './PerspectiveRightPanel';
import PerspectivePanel from "./PerspectivePanel";
import SettingModal from "../modals/SettingModal";
import AudioConvertModal from "../modals/AudioConvertModal";
import VideoConvertModal from './../modals/VideoConvertModal';
import ImagesToIcoModal from "../modals/ImagesToIcoModal";
import ToolPanel from "./ToolPanel";

interface IHomeState {
    bottomHeight: number;
    leftWidth: number;
    rightWidth: number;
}

interface IHomeProps extends RouteComponentProps<any> {
    siteInfo: ISite|null|undefined;
    userInfo: IUserInfo;
    maxWidget: number;
    lang: string;
    panes: IPanes;
    activePane: string|undefined;
    currentModalName: string|null;
    bottomWidget: string|null;
    bottomWidgetHeight: number;
    rightWidget: string|null;
    rightWidgetWidth: number;
    leftWidget: string|null;
    leftWidgetWidth: number;
    mainDockPanelStyle: any;
    toolbars: IToolbar[];
    openfiles: IOpenFiles;
    blogNavTreeData: IBlogNav[];
    blogSha: string|null;
    navSelectedKey: string;
    navExpandedKeys: string[];
    addNavTreeNodeType: string;
    changeLang: Function;
    getToolbarData: Function;
    updateWidget: Function;
    updateModalName: Function;
    openFile: Function;
    updateBlogNavTreeConfig: Function;
}

const mapStateToProps = (state: any) => {
    return {
        lang: state.setting.lang,
        siteInfo: state.setting.siteInfo,
        maxWidget: state.setting.maxWidget,
        leftWidget: state.setting.leftWidget,
        leftWidgetWidth: state.setting.leftWidgetWidth,
        rightWidget: state.setting.rightWidget,
        rightWidgetWidth: state.setting.rightWidgetWidth,
        bottomWidget: state.setting.bottomWidget,
        bottomWidgetHeight: state.setting.bottomWidgetHeight,
        mainDockPanelStyle: state.setting.mainDockPanelStyle,
        blogNavTreeData: state.blog.navTreeData,
        blogSha: state.blog.sha,
        navSelectedKey: state.blog.navSelectedKey,
        navExpandedKeys: state.blog.navExpandedKeys,
        addNavTreeNodeType: state.blog.addNavTreeNodeType,
        toolbars: state.setting.toolbars,
        currentModalName: state.editor.currentModalName,
        openfiles: state.openfiles,
        activePane: state.editor.activePane,
        userInfo: state.account.userInfo,
        panes: state.panes
    }
};

const mapDispatchTpProps = {
    changeLang,
    getToolbarData,
    updateWidget,
    updateModalName,
    openFile,
    updateBlogNavTreeConfig
};

const baseCSSProperties: CSSProperties = {
    position: 'absolute',
    overflow: 'hidden',
    left: 0,
    top: 0,
    right: 0
};

const perspectivePanelSplitLayoutCacheKey = 'home_perspective_panel_split_layout';

class Home extends React.Component<IHomeProps, IHomeState> {

    private mainDockPanel: any = null;

    constructor(props: IHomeProps) {
        super(props);
        this.state = {
            bottomHeight: NaN,
            leftWidth: NaN,
            rightWidth: NaN,
        }
    }

    handleLangChange = (lang: string) => {
        this.props.changeLang(lang);
    };

    onSecondaryPaneSizeChange = (size: number, pos: number) => {
        let perspectivePanelSplitLayoutData = {
            bottomHeight: this.state.bottomHeight,
            leftWidth: this.state.leftWidth,
            rightWidth: this.state.rightWidth
        }
        switch (pos) {
            case WidgetPos_Bottom:
                perspectivePanelSplitLayoutData.bottomHeight = size;
                break;
            case WidgetPos_Left:
                perspectivePanelSplitLayoutData.leftWidth = size;
                break;
            case WidgetPos_Right:
                perspectivePanelSplitLayoutData.rightWidth = size;
                break;
        }
        LocalStorageUtil.setItem(perspectivePanelSplitLayoutCacheKey, JSON.stringify(perspectivePanelSplitLayoutData));
    }

    generateSplitLayoutPanel = () => {
        switch (this.props.maxWidget) {
            case WidgetPos_Bottom:
                return (
                    <div className="splitLayoutPanel">
                        <PerspectiveBottomPanel />
                    </div>
                );
            case WidgetPos_Left:
                return (
                    <div className="splitLayoutPanel">
                        <PerspectiveLeftPanel />
                    </div>
                );
            case WidgetPos_Right:
                return (
                    <div className="splitLayoutPanel">
                        <PerspectiveRightPanel />
                    </div>
                );
            case WidgetPos_Center:
                return (
                    <div className="splitLayoutPanel">
                        <PerspectivePanel />
                    </div>
                );
            default:
                const {bottomWidget, leftWidget, rightWidget} = this.props;
                const {bottomHeight, leftWidth, rightWidth} = this.state;
                let showRightWidget: boolean = !!rightWidget;
                if (rightWidget == WidgetName_Property_Explorer) {
                    const activePane = this.props.activePane ? this.props.panes[this.props.activePane] : null;
                    let currentOpenFile: IOpenFile|null = null;
                    if (activePane && activePane.activeFile && this.props.openfiles && this.props.activePane) {
                        currentOpenFile = this.props.openfiles[activePane.activeFile];
                    }
                    showRightWidget = currentOpenFile && currentOpenFile.editing ? true : false;
                }
                return (
                    <div className="splitLayoutPanel">
                        <SplitterLayout
                            primaryIndex={0}
                            secondaryInitialSize={bottomHeight}
                            onSecondaryPaneSizeChange={(size: number) => this.onSecondaryPaneSizeChange(size, WidgetPos_Bottom)}
                            vertical>
                            <SplitterLayout
                                primaryIndex={1}
                                secondaryMinSize={this.props.leftWidgetWidth}
                                secondaryInitialSize={leftWidth}
                                onSecondaryPaneSizeChange={(size: number) => this.onSecondaryPaneSizeChange(size, WidgetPos_Left)}>
                                {
                                    leftWidget && <PerspectiveLeftPanel />
                                }
                                <SplitterLayout
                                    primaryIndex={0}
                                    secondaryInitialSize={rightWidth}
                                    onSecondaryPaneSizeChange={(size: number) => this.onSecondaryPaneSizeChange(size, WidgetPos_Right)}>
                                    <PerspectivePanel />
                                    {
                                        showRightWidget && <PerspectiveRightPanel />
                                    }
                                </SplitterLayout>
                            </SplitterLayout>
                            {
                                bottomWidget && <PerspectiveBottomPanel />
                            }
                            
                        </SplitterLayout>
                    </div>
                );
        }
    };

    checkDisabled = (action: string) => {
        switch (action) {
            case 'save':
            case 'saveAll':
                let needUpload = false;
                Object.keys(this.props.openfiles).map(key => {
                    const $openFile = this.props.openfiles[key];
                    if ($openFile.needUpload) {
                        needUpload = true;
                    }
                });
                return !needUpload;
            case 'newFile':
                return !(this.props.blogSha && this.props.navSelectedKey && this.props.addNavTreeNodeType == '');
        }
        return false;
    }

    checkIsCheck = (action: string) => {
        let isChecked = false;
        return isChecked ? <i className="iconfont">&#xe60a;</i> : null;
    }

    onMenuClick = (e: any) => {
        let action: string = e.item.props['data-action'];
		if (action) {
            this.doAction(action);
        }
    };

    doAction = (action: string) => {
        switch (action) {
            case 'siteSetting':
                this.props.updateModalName(Modal_Setting);
                break;
            case 'audioConvert':
                this.props.updateModalName(Modal_Audio_Convert);
                break;
            case 'videoConvert':
                this.props.updateModalName(Modal_Video_Convert);
                break;
            case 'imagesToIco':
                this.props.updateModalName(Modal_Images_To_Ico);
                break;
            case 'about':
                this.props.openFile({
                    title: formatMessage({id: 'app.about'}),
                    path:`about.md`
                });
                break;
            case 'newFile':
                if (this.props.leftWidget == WidgetName_Blog_Explorer) {
                    this.handleNewBlogFile();
                }
                break;
            case 'newFolder':
                if (this.props.leftWidget == WidgetName_Blog_Explorer) {
                    this.handleNewBlogFolder();
                }
                break;
            case 'save':

                break;
            case 'saveAll':

                break;
        }
    };

    handleNewBlogFolder = () => {
        const data = [...this.props.blogNavTreeData];
        let index = 0;
        data.map(item => {
            if (item.key) {
                const arr = item.key.split("-");
                index = Math.max(index, parseInt(arr[arr.length - 1]));
            }
        });
        data.push({
            closeIcon: `${process.env.PUBLIC_URL}/assets/svg/folder-public.svg`,
            openIcon: `${process.env.PUBLIC_URL}/assets/svg/folder-public-open.svg`,
            icon: generateTreeItemIcon,
            key: `key-${index + 1}`,
            isEditable: true,
            children: []
        });
        
        this.props.updateBlogNavTreeConfig({
            navTreeData: data,
            navEditNodeTitle: '',
            addNavTreeNodeType: ADD_NAV_TREE_NODE_TYPE_FOLDER
        });
    };

    handleNewBlogFile = () => {
        const data = [...this.props.blogNavTreeData];
        const expandedKeys = [...this.props.navExpandedKeys];
        let key = getTreeParentKey(this.props.navSelectedKey, data);
        key = key || this.props.navSelectedKey;
        if (key) {
            data.map(item => {
                if (item.key == key) {
                    let cIndex = 0;
                    if (!item.children) {
                        item.children = [];
                    } else {
                        item.children.map((_item: any) => {
                            const arr = _item.key.split("-");
                            cIndex = Math.max(cIndex, arr[arr.length - 1]);
                        });
                    }
                    const nodeKey = `${item.key}-${cIndex + 1}`;
                    item.children.push({
                        icon: <img src={`${process.env.PUBLIC_URL}/assets/svg/document.svg`} style={{marginTop: -5}} />,
                        key: nodeKey,
                        isEditable: true
                    });
                    expandedKeys.push(nodeKey);
                }
            });
        }
        
        this.props.updateBlogNavTreeConfig({
            navTreeData: data,
            navEditNodeTitle: '',
            navAutoExpandParent: true,
            navExpandedKeys: expandedKeys,
            addNavTreeNodeType: ADD_NAV_TREE_NODE_TYPE_FILE
        });
    };

    generateToolbarMenu = (data: any[]) => {
        return (
            <Menu className="editor-drop-menu toolbar-menu" onClick = {this.onMenuClick}>
                { this.generateToolbarMenuItem(data) }
            </Menu>
        );
    };

    generateToolbarMenuItem = (data: any[]) => {
        return data.map((item: any, i: number) => {
            if (item.children && item.children.length > 0) {
                return (
                    <Menu.SubMenu key={item.name} title={item.label}>
                        { this.generateToolbarMenuItem(item.children)}
                    </Menu.SubMenu>
                );
            } else if (item.hasOwnProperty('divider')) {
                return (<Menu.Divider key={i} />);
            } else {
                return (
                    <Menu.Item 
                        key={i} 
                        data-action={item.action}
                        disabled={this.checkDisabled(item.action)} >
                        <div className="icon">{ item.isCheckbox ?  this.checkIsCheck(item.action) : generateIcon(item.icon) }</div>
						<div className="text">{ formatMessage({id: item.label}) }</div>
                        {
                            item.hotKey != '' && <div className="rightside">{item.hotKey}</div>
                        }
                    </Menu.Item>
                );
            }
        });
    };

    generateToolbarBtn = (data: any, index: number) => {
        return (
            <Button
                key ={index}
                onClick={(e) => this.doAction(data.action)}
                className='menu-btn'>
                {data.icon && <div className="nav-icon">{ generateIcon(data.icon) }</div>}
                <span className="nav-title">{formatMessage({id: data.label})}</span>
            </Button>
        );
    };

    generateToolbars = () => {
        if (this.props.toolbars) {
            return this.props.toolbars.map((item, index) => {
                if (item.children && item.children.length > 0) {
                    return (
                        <Dropdown
                            overlay={this.generateToolbarMenu(item.children)}
                            trigger={['click']}
                            key ={index}
                            getPopupContainer={(): any => {
                                return document.getElementById('root');
                            }}>
                            { this.generateToolbarBtn(item, index) }
                        </Dropdown>
                    );
                } else {
                    return this.generateToolbarBtn(item, index);
                }
            });
        }
        return null;
    }

    componentWillMount(): void {
        let bottomHeight = this.props.bottomWidgetHeight;
        let leftWidth = this.props.leftWidgetWidth;
        let rightWidth = this.props.rightWidgetWidth;
        let perspectivePanelSplitLayoutStr = LocalStorageUtil.getItem(perspectivePanelSplitLayoutCacheKey);
        if (perspectivePanelSplitLayoutStr) {
            let perspectivePanelSplitLayoutData = JSON.parse(perspectivePanelSplitLayoutStr);
            bottomHeight = perspectivePanelSplitLayoutData.bottomHeight || bottomHeight;
            leftWidth = perspectivePanelSplitLayoutData.leftWidth || leftWidth;
            rightWidth = perspectivePanelSplitLayoutData.rightWidth || rightWidth;
        }
        this.setState({
            bottomHeight,
            leftWidth,
            rightWidth
        });
        this.props.getToolbarData();
    }

    componentDidMount(): void {
        if (this.mainDockPanel) {
            addHTMLElementStyle(this.mainDockPanel, "mainDockPanel::before", this.props.mainDockPanelStyle);
        }
        let cnzzSiteId = this.props.siteInfo ? this.props.siteInfo.cnzzSiteId : "1278996152";
        let sc = document.createElement("script");
        sc.src = `https://s9.cnzz.com/z_stat.php?id=${cnzzSiteId}&online=2`;
        document.body.appendChild(sc);
    }

    componentWillReceiveProps(nextProps: Readonly<IHomeProps>, nextContext: any): void {
        if (this.mainDockPanel && this.props.mainDockPanelStyle != nextProps.mainDockPanelStyle) {
            addHTMLElementStyle(this.mainDockPanel, "mainDockPanel::before", nextProps.mainDockPanelStyle);
        }
    }

    render() {
        let mainDockPanelClassname = 'mainDockPanel';
        if (this.props.currentModalName) {
            mainDockPanelClassname += ' frosted-glass';
        }
        const activePane = this.props.activePane ? this.props.panes[this.props.activePane] : null;
        let currentOpenFile: IOpenFile|null = null;
        if (activePane && activePane.activeFile && this.props.openfiles && this.props.activePane) {
            currentOpenFile = this.props.openfiles[activePane.activeFile];
        }

        return (
            <div style={{
                position: 'absolute',
                overflow: 'hidden',
                left: 0,
                top: 0,
                right: 0,
                bottom: 0
            }}>
                <SettingModal />
                <AudioConvertModal />
                <VideoConvertModal />
                <ImagesToIcoModal />
                <div className={mainDockPanelClassname} ref={(value) => this.mainDockPanel = value}>
                    {/* ------------ MainMenuPanel -------------------- */}
                    <div style={{...baseCSSProperties, height: 40}}>
                        <div className="mainMenuPanel">
                            <div className="content">
                                <div className="logo">
                                    <div style={{width: 200, height: 40, padding: 2}}>
                                        <img 
                                            src={this.props.siteInfo && this.props.siteInfo.logo ? this.props.siteInfo.logo : logo} 
                                            height={34} 
                                            alt={this.props.siteInfo ? this.props.siteInfo.title : ''} 
                                            />
                                    </div>
                                </div>
                                <div className="nav">
                                    {this.generateToolbars()}
                                </div>
                                <div className="lang">
                                    <div 
                                        className="button-group" 
                                        style={{
                                            width: 200, 
                                            height: 20,
                                            marginTop: 9,
                                            marginLeft: 20, 
                                            marginRight: 20, 
                                            padding: 0
                                        }}>
                                        <div
                                            className={this.props.lang == 'zh' ? 'active' : ''}
                                            onClick={() => {
                                                this.handleLangChange('zh');
                                            }}>
                                            中文(简体)
                                        </div>
                                        <div
                                            className={this.props.lang == 'en' ? 'active' : ''}
                                            onClick={() => {
                                                this.handleLangChange('en');
                                            }}>
                                            English
                                        </div>
                                    </div>
                                </div>
                                <div className="toolBar">
                                    <UserToolbar />
                                </div>
                            </div>
                        </div>
                    </div>
                    {/* ------------ ToolbarPanel -------------------- */}
                    <div style={{...baseCSSProperties, top: 40, height: 40}}>
                        <ToolPanel />
                    </div>
                    {/* ------------ NoToolbarPanel -------------------- */}
                    <div style={{...baseCSSProperties, display: 'none', bottom: 0}}>
                        <div className="noToolbarPanel">
                            
                        </div>
                    </div>
                    {/* ------------ StatusPanel -------------------- */}
                    <div style={{...baseCSSProperties, top: undefined, bottom: 0, height: 18}}>
                        <div className="statusPanel">
                            <div style={{float: 'left', height: 'inherit', whiteSpace: 'nowrap', marginLeft: 1}}>
                                <span id='cnzz_stat_icon_1278996152' style={{color: 'rgba(255, 255, 255, 0.3)', marginLeft: 10}}></span>
                            </div>
                            <div style={{float: 'left', height: 'inherit', whiteSpace: 'nowrap', marginLeft: 960}}>

                            </div>
                        </div>
                    </div>
                    {/* ------------ ActionPanel -------------------- */}
                    <div style={{...baseCSSProperties, display: 'none', bottom: 0}}>
                        <div className="actionPanel">

                        </div>
                    </div>
                    {/* ------------ PerspectivePanel -------------------- */}
                    <div style={{...baseCSSProperties, top: 80, bottom: 18}}>
                        <div className="perspectivePanel">
                            <div style={{...baseCSSProperties, right: undefined, width: '100%', height: '100%'}}>
                                {/* ------------ rightPanel -------------------- */}
                                <div style={{...baseCSSProperties, left: undefined, width: 24}}>
                                    <div className="right">
                                        <div className="content rotate90deg">
                                            {
                                                currentOpenFile && currentOpenFile.editing && (
                                                    <div
                                                        className={"partButton rotate180deg" + (this.props.rightWidget == WidgetName_Property_Explorer ? " selected" : "")}
                                                        onClick={() => {
                                                            this.props.updateWidget(WidgetName_Property_Explorer, WidgetPos_Right);
                                                        }}>
                                                        <div className="icon" style={{marginTop: -6}}><Property /></div>
                                                        <div className="label">
                                                            { formatMessage({id: 'app.property'})}
                                                        </div>
                                                    </div>
                                                )
                                            }
                                        </div>
                                    </div>
                                </div>
                                {/* ------------ leftPanel -------------------- */}
                                <div style={{...baseCSSProperties, right: undefined, bottom: 0, width: 24}}>
                                    <div className="left">
                                        <div className="content rotate90deg">
                                            <div
                                                className={"partButton rotate180deg" + (this.props.leftWidget == WidgetName_Blog_Explorer ? " selected" : "")}
                                                onClick={() => {
                                                    this.props.updateWidget(WidgetName_Blog_Explorer, WidgetPos_Left);
                                                }}>
                                                <div className="icon" style={{marginTop: -6}}><Blogger /></div>
                                                <div className="label">
                                                    { formatMessage({id: 'app.blogs'})}
                                                </div>
                                            </div>
                                            {
                                                this.props.userInfo && 
                                                <div
                                                    className={"partButton rotate180deg" + (this.props.leftWidget == WidgetName_Workspace_Explorer ? " selected" : "")}
                                                    onClick={() => {
                                                        this.props.updateWidget(WidgetName_Workspace_Explorer, WidgetPos_Left);
                                                    }}>
                                                    <div className="icon" style={{marginTop: -6}}><CodeOptimization /></div>
                                                    <div className="label">
                                                        { formatMessage({id: 'app.workspace'})}
                                                    </div>
                                                </div>
                                            }
                                        </div>
                                    </div>
                                </div>
                                {/* ------------ bottomPanel -------------------- */}
                                <div style={{...baseCSSProperties, top: undefined, left: 24, right: 24, height: 24, bottom: 0}}>
                                    <div className="bottom">
                                        <div className="content">

                                        </div>
                                    </div>
                                </div>
                                {/* ------------ SplitLayoutPanel -------------------- */}
                                <div style={{...baseCSSProperties, left: 24, right: 24, bottom: 24}}>
                                    { this.generateSplitLayoutPanel() }
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(Home));
