import { RouteComponentProps, withRouter } from "react-router";
import * as React from "react";
import { connect } from "react-redux";
import { updateWidget } from "../../actions/settingActions";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    bottomWidget: string|null;
    updateWidget: any;
}

const mapStateToProps = (state: any) => {
    return {
        bottomWidget: state.setting.bottomWidget,
    }
};

const mapDispatchTpProps = {
    updateWidget
};

class PerspectiveBottomPanel extends React.Component<IProps, IState> {

    generateContent = () => {

    };

    render() {
        return (
        <>{ this.generateContent() }</>
        );
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(PerspectiveBottomPanel));